-- Truth placement example: enforce uniqueness and prevent duplicates at the DB
CREATE TABLE users (
  id BIGSERIAL PRIMARY KEY,
  email TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Database-level invariant: no two users can share an email
CREATE UNIQUE INDEX users_email_unique ON users (lower(email));

-- If multiple API servers race to create the same email, the DB is authoritative.
-- The application handles the constraint violation and returns a safe error.

// Node/Fetch example: deadline + bounded retries with jitter + idempotency
// Goal: control latency and retry budget while staying correct under partial failure.

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function jitter(ms) {
  return Math.floor(ms * (0.5 + Math.random()));
}

async function fetchWithBudget(url, {
  method = 'GET',
  headers = {},
  body,
  timeoutMs = 200,        // per-hop latency budget
  maxAttempts = 2,        // retry budget: 1 retry
  idempotencyKey          // required for POST/PUT retries
} = {}) {
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    const controller = new AbortController();
    const t = setTimeout(() => controller.abort(), timeoutMs);

    try {
      const res = await fetch(url, {
        method,
        headers: {
          ...headers,
          ...(idempotencyKey ? { 'Idempotency-Key': idempotencyKey } : {})
        },
        body,
        signal: controller.signal
      });

      // Retry only on transient failures
      if (res.status >= 500 && res.status <= 599 && attempt < maxAttempts) {
        await sleep(jitter(30 * attempt));
        continue;
      }

      return res;
    } catch (err) {
      // Network errors/timeouts may be transient; still bounded by attempts
      if (attempt < maxAttempts) {
        await sleep(jitter(30 * attempt));
        continue;
      }
      throw err;
    } finally {
      clearTimeout(t);
    }
  }
}

// Notes:
// - Don't retry non-idempotent writes without an idempotency key.
// - Propagate request deadlines across service boundaries where possible.
